"use strict";(self.webpackChunkhamrang_log=self.webpackChunkhamrang_log||[]).push([[5894],{6042:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"blog-docusaurus","metadata":{"permalink":"/blog/blog-docusaurus","editUrl":"https://github.com/eeheueklf/eeheueklf.github.io/tree/main/blog/2026-03-26.md","source":"@site/blog/2026-03-26.md","title":"\ube14\ub85c\uadf8 \uc0c8 \ub2e8\uc7a5 with Docusaurus\ud83e\udd95","description":"","date":"2026-03-26T00:00:00.000Z","formattedDate":"2026\ub144 3\uc6d4 26\uc77c","tags":[],"readingTime":0,"hasTruncateMarker":false,"authors":[],"frontMatter":{"slug":"blog-docusaurus","title":"\ube14\ub85c\uadf8 \uc0c8 \ub2e8\uc7a5 with Docusaurus\ud83e\udd95","date":"2026-03-26T00:00:00.000Z"},"unlisted":false,"nextItem":{"title":"Next.js\uac00 \ud568\uc815\uc774\uc5c8\ub358 \ud0c0\uc790 \uc5f0\uc2b5 \ud504\ub85c\uc81d\ud2b8 \ud68c\uace0","permalink":"/blog/next-sidepj"}},"content":""},{"id":"next-sidepj","metadata":{"permalink":"/blog/next-sidepj","editUrl":"https://github.com/eeheueklf/eeheueklf.github.io/tree/main/blog/2026-03-21.md","source":"@site/blog/2026-03-21.md","title":"Next.js\uac00 \ud568\uc815\uc774\uc5c8\ub358 \ud0c0\uc790 \uc5f0\uc2b5 \ud504\ub85c\uc81d\ud2b8 \ud68c\uace0","description":"\ucd5c\uc2e0 \ud2b8\ub80c\ub4dc\uc778 Next.js\ub97c \ud559\uc2b5\ud558\uace0 \uc801\uc6a9\ud588\ub358 \uc801\uc6a9\uae30\uc785\ub2c8\ub2e4.","date":"2026-03-21T00:00:00.000Z","formattedDate":"2026\ub144 3\uc6d4 21\uc77c","tags":[],"readingTime":3.135,"hasTruncateMarker":false,"authors":[],"frontMatter":{"slug":"next-sidepj","title":"Next.js\uac00 \ud568\uc815\uc774\uc5c8\ub358 \ud0c0\uc790 \uc5f0\uc2b5 \ud504\ub85c\uc81d\ud2b8 \ud68c\uace0","date":"2026-03-21T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"\ube14\ub85c\uadf8 \uc0c8 \ub2e8\uc7a5 with Docusaurus\ud83e\udd95","permalink":"/blog/blog-docusaurus"},"nextItem":{"title":"[\ud68c\uace0] \ud504\ub85c\uadf8\ub798\uba38\uc2a4 \uae30\ucd08 \uc785\ubb38 \ub2ec\uc131 \ud6c4\uae30 \ud83e\udd73\ud83c\udf89","permalink":"/blog/programmers"}},"content":"*\ucd5c\uc2e0 \ud2b8\ub80c\ub4dc\uc778 Next.js\ub97c \ud559\uc2b5\ud558\uace0 \uc801\uc6a9\ud588\ub358 \uc801\uc6a9\uae30\uc785\ub2c8\ub2e4.*\\n\\n\ube14\ub85c\uadf8\ub97c \ub9cc\ub4e4\uba70 `Next.js`\ub97c \ub9db\ubcf8 \ub4a4, **\uc774\uac70 \ubb3c\uac74\uc774\ub2e4**\ub77c\ub294 \uc0dd\uac01\uc774 \ub4e4\uc5c8\ub2e4.\\n\\n\ubc30\ud3ec\ub3c4 \ube60\ub974\uace0 \ub9ac\uc561\ud2b8\ub791\ub3c4 \ube44\uc2b7\ud574\uc11c, \ubc14\ub85c \ub2e4\uc74c \ud504\ub85c\uc81d\ud2b8 \ud504\ub808\uc784\uc6cc\ud06c\ub85c \uc120\ud0dd\ud588\ub2e4.\\n\\n\uadf8\ub807\uac8c 2\uba85\uc774\uc11c \uc57c\uc2ec\ucc28\uac8c \uc2dc\uc791\ud55c \ud0c0\uc790 \uc5f0\uc2b5 \uc0ac\uc774\ud2b8 \uc0ac\uc774\ub4dc \ud504\ub85c\uc81d\ud2b8 \\n[TYLE](https://tyletype.vercel.app)\\n\\n\\n![TYLE](./img/TYLE.png)\\n\\n\ucc98\uc74c\uc5d4 \ubaa8\ub4e0 \uac8c \uc21c\uc870\ub85c\uc6e0\ub2e4.\\n\\n`Vercel`\uc5d0\uc11c\uc758 \ubc30\ud3ec\ub294 \uc21c\uc2dd\uac04\uc774\uc5c8\uace0, \ub9ac\uc561\ud2b8 \ud588\ub358\ub300\ub85c \uad6c\ud604\ub3c4 \ube60\ub974\uac8c \ud588\ub2e4.\\n\\n\ud558\uc9c0\ub9cc \ud504\ub85c\uc81d\ud2b8\uac00 \uc9c4\ud589\ub420\uc218\ub85d \ubb54\uac00 \uc774\uc0c1\ud568\uc744 \ub290\uaf08\ub2e4.\\n\\n![\uc774\uc0c1\ud558\ub2e4](./img/\uc774\uc0c1\ud558\ub2e4.png)\\n\\n**1. \uc774\uac70 `use Client` \uc774\ub807\uac8c \ub9ce\uc774 \uc4f0\uba74 \uc548\ub420 \uac83 \uac19\uc740\ub370**\\n\\n`Next.js`\uac00 SSR(\uc11c\ubc84 \uc0ac\uc774\ub4dc \ub80c\ub354\ub9c1)\uc5d0 \uac15\uc810\uc774 \uc788\uc74c\uc5d0\ub3c4 \uc0ac\uc774\ud2b8 \ucd08\uae30 \uba54\uc778\ud654\uba74 \ub80c\ub354\ub9c1 \uc18d\ub3c4\uac00 \ub108\ubb34 \uae38\uc5c8\ub2e4.  \\n(\uac70\uc758 5\ucd08 \uc774\uc0c1?)\\n\\n\ud0c0\uc790 \uc5f0\uc2b5 \ud2b9\uc131\uc0c1 \uc2e4\uc2dc\uac04 \ud0a4\ubcf4\ub4dc \uc774\ubca4\ud2b8\uc640 \uc0c1\ud0dc \uc5c5\ub370\uc774\ud2b8\uac00 70% \uc774\uc0c1\uc774\uc5c8\uae30 \ub54c\ubb38\uc5d0  \\n\ud654\uba74\uc5d0 \uac70\uc758 \ubaa8\ub4e0 \uacf3\uc5d0 `use client`\uac00 \ud544\uc694\ud588\uace0, .\\n\\n\\n**2. SEO \uc4f8\ub370\uac00 \uc5c6\ub124**\\n\\n\uac80\uc0c9 \uc5d4\uc9c4 \ucd5c\uc801\ud654\uac00 \uc7a5\uc810\uc774\ub77c\uc9c0\ub9cc, \ud0c0\uc790 \uc5f0\uc2b5 \uc0ac\uc774\ud2b8\uc5d4 \ud14d\uc2a4\ud2b8 \ucf58\ud150\uce20\uac00 \uc5c6\uae30 \ub54c\ubb38\uc5d0\\n\\n\ud0a4\ubcf4\ub4dc\uc640 \uae00\uadc0\ub9cc \uc788\ub294 \uc11c\ube44\uc2a4\uc5d0\uc11c \uc7a5\uc810\uc744 \ubc1c\ud718 \ud560 \uc218\uac00 \uc5c6\uc5c8\ub2e4.\\n\\n\\n**3. \ud55c\uae00 \uc785\ub825\uacfc \ub80c\ub354\ub9c1**\\n\\n\ud2b9\ud788 \ud55c\uae00 \uc785\ub825\uc774 \uc790+\ubaa8\uc74c\uc774 \ud569\uccd0\uc9c0\ub294 \ud615\ud0dc\ub77c \uc0c1\ud0dc \uc5c5\ub370\uc774\ud2b8\uac00 \ud2b9\uc218\ud55c\ub370,\\n\\n( \uc870\ud569 \uc911\uc778 \uae00\uc790\uac00 \uc0c1\ud0dc\uc640 \ub3d9\uae30\ud654\ub418\uba74\uc11c \ubd88\ud544\uc694\ud55c \ub80c\ub354\ub9c1\uc744 \uc720\ubc1c\ud55c\ub2e4\ub294 \uc810\uc785\ub2c8\ub2e4.)\\n\\n\ubd88\ud544\uc694\ud55c \ub80c\ub354\ub9c1\uacfc \uc5d4\ud130 \ud0a4 \uc911\ubcf5 \uc774\ubca4\ud2b8 \uc774\uc288 \ub4f1 \ud074\ub77c\uc774\uc5b8\ud2b8 \ucd5c\uc801\ud654\uc5d0 \uc9d1\uc911\ud574\uc57c \ud558\uae30 \ub54c\ubb38\uc5d0\\n\\n\ud575\uc2ec\uc778 \ud0c0\uc774\ud551 \ub85c\uc9c1\uc740 \uc11c\ubc84\uac00 \ub3c4\uc640\uc904 \uc218 \uc5c6\uae30 \ub54c\ubb38\uc5d0 \uc2e4\uc81c \uc131\ub2a5\uc758 \ud575\uc2ec\uc740 \ud074\ub77c\uc774\uc5b8\ud2b8 \ucd5c\uc801\ud654\uc5d0\uc788\uc5c8\ub2e4.\\n\\n\uc624\ud788\ub824 \uc544\ud0a4\ud14d\ucc98\ub9cc \ubcf5\uc7a1\ud574\uc9c0\uace0 \uc788\uc5c8\ub2e4.\\n\\n\uae68\ub2ec\uc74c : \uae30\uc220\uc740 \ub3c4\uad6c\uc77c \ubfd0\uc774\ub2e4.\\n\\n\uace0\ub824 \uc5c6\ub294 \uae30\uc220 \ub3c4\uc785\uc740 \uc624\ud788\ub824 \uc544\ud0a4\ud14d\ucc98\ub97c \ubcf5\uc7a1\ud558\uac8c \ub9cc\ub4e4\uace0\\n\\n\uba38\ub9ac\uac00 \uc544\ud30c\uc9c8 \uc218 \uc788\ub2e4@.!\\n\\n\ub2e4\uc74c \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\ub294 SEO\uc640 \ucd08\uae30 \ub85c\ub529 \uc18d\ub3c4\uac00 \uc911\uc694\ud588\uae30\uc5d0 Next.js\ub97c \uc120\ud0dd\ud588\uc9c0\ub9cc\\n\\n\ud0c0\uc790 \uc5f0\uc2b5 \uac19\uc740 \ud504\ub85c\uc81d\ud2b8\ub77c\uba74 \uac00\ubcbc\uc6b4 \ud658\uacbd\uc774 \ub354 \uc801\ud569\ud588\uc744 \uac83 \uac19\ub2e4."},{"id":"programmers","metadata":{"permalink":"/blog/programmers","editUrl":"https://github.com/eeheueklf/eeheueklf.github.io/tree/main/blog/2025-09-26.md","source":"@site/blog/2025-09-26.md","title":"[\ud68c\uace0] \ud504\ub85c\uadf8\ub798\uba38\uc2a4 \uae30\ucd08 \uc785\ubb38 \ub2ec\uc131 \ud6c4\uae30 \ud83e\udd73\ud83c\udf89","description":"\ud504\ub860\ud2b8\uc5d4\ub4dc \ucf54\ub529\ud14c\uc2a4\ud2b8 \uc900\ube44 \uacb8 JS \uae30\ubcf8\uae30 \uc775\ud788\uae30\ub97c \ubaa9\ud45c\ub85c \ud504\ub85c\uadf8\ub798\uba38\uc2a4 \uae30\ucd08 \ubc0f \uc785\ubb38 \ud2b8\ub808\uc774\ub2dd\uc744 3\uc8fc \ub3d9\uc548 \ud480\uc5c8\ub2e4.","date":"2025-09-25T00:00:00.000Z","formattedDate":"2025\ub144 9\uc6d4 25\uc77c","tags":[],"readingTime":2.29,"hasTruncateMarker":false,"authors":[],"frontMatter":{"slug":"programmers","title":"[\ud68c\uace0] \ud504\ub85c\uadf8\ub798\uba38\uc2a4 \uae30\ucd08 \uc785\ubb38 \ub2ec\uc131 \ud6c4\uae30 \ud83e\udd73\ud83c\udf89","sidebar_position":0,"date":"2025-09-25T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"Next.js\uac00 \ud568\uc815\uc774\uc5c8\ub358 \ud0c0\uc790 \uc5f0\uc2b5 \ud504\ub85c\uc81d\ud2b8 \ud68c\uace0","permalink":"/blog/next-sidepj"},"nextItem":{"title":"\uc778\ud2b8\ub85c","permalink":"/blog/intro"}},"content":"\ud504\ub860\ud2b8\uc5d4\ub4dc \ucf54\ub529\ud14c\uc2a4\ud2b8 \uc900\ube44 \uacb8 JS \uae30\ubcf8\uae30 \uc775\ud788\uae30\ub97c \ubaa9\ud45c\ub85c \ud504\ub85c\uadf8\ub798\uba38\uc2a4 \uae30\ucd08 \ubc0f \uc785\ubb38 \ud2b8\ub808\uc774\ub2dd\uc744 3\uc8fc \ub3d9\uc548 \ud480\uc5c8\ub2e4.  \\n\uae30\ucd08\uc640 \uc785\ubb38 \uac01 25\uc77c\uc529 `Lv.0` \ubb38\uc81c\ub97c \ud480\uc5b4\ubcf4\ub294 \uacfc\uc815\uc774\uc5c8\ub294\ub370, \uc804\uacf5\uc790\ub77c \ud558\ub8e8\uc5d0 \uae30\ucd08+\uc785\ubb38 `2 Day`\uc529 \ub2ec\ub838\ub2e4.\\n\\n\ucd08\ubc18\uc5d0\ub294 1\uc2dc\uac04 \uc815\ub3c4 \uac78\ub838\uace0, \ud6c4\ubc18\uc5d0\ub294 2\uc2dc\uac04, \uc5b4\ub824\uc6b8 \ub54c\ub294 3\uc2dc\uac04\uae4c\uc9c0 \ubb38\uc81c \ud480\uc774\uc5d0 \uc2dc\uac04\uc744 \ub4e4\uc600\ub2e4.\\n\\n\uadf8\ub3d9\uc548 \ud504\ub860\ud2b8\uc5d4\ub4dc \uad6c\ud604\uc5d0 `JavaScript`\ub97c \uc4f0\uae34 \ud588\uc9c0\ub9cc \uae30\ucd08\ubd80\ud130 \uccb4\uacc4\uc801\uc73c\ub85c \ubc30\uc6b4 \uac74 \uc544\ub2c8\uc5c8\ub2e4. \uadf8\ub798\uc11c \uba54\uc11c\ub4dc \ud558\ub098\ud558\ub098 \uc54c\uc544\uac00\uba74\uc11c \ud480\uc5c8\ub294\ub370, \uacfc\uc815\uc744 \uc644\ub8cc\ud558\ub294 \uc2dc\uc810\uc5d0\uc11c \ubcf4\ub2c8 \uac01 \uba54\uc11c\ub4dc\uc758 \uc4f0\uc784\uc0c8\ub97c \uc775\ud788\uace0 \ubb38\uc790\uc5f4\uacfc \ubc30\uc5f4\uc744 \uc9d1\uc911\uc801\uc73c\ub85c \uacf5\ub7b5\ud560 \uc218 \uc788\uc5b4\uc11c \uc88b\uc558\ub2e4.\\n\\n\ub4dc\ub514\uc5b4 JS\uc758 \uae30\ucd08\ub97c \uc81c\ub300\ub85c \ub5c0 \ub290\ub08c \ud83d\ude0a\ud83d\ude05\\n\\n\\n![alt text](./img/emoji1.png)\\n\\n\\n`Lv.0`\uc778\ub370\ub3c4 \uc27d\uc9c0 \uc54a\uc740 \ubb38\uc81c\ub4e4\uc774 \uc11e\uc5ec \uc788\uc5c8\uc9c0\ub9cc, `JavaScript`\uc5d0\ub294 \ub2e4\ub978 \uc5b8\uc5b4\uc5d0\uc11c \ubcfc \uc218 \uc5c6\ub294 \uae30\ud2b9\ud55c \uba54\uc11c\ub4dc\uac00 \ucc38 \ub9ce\uc558\ub2e4. \uae38\uac8c \ud480\uc5b4\uc57c \ud560 \ub85c\uc9c1\uc744 \ud55c \uc904\ub85c \uc904\uc5ec\uc8fc\ub294 \uba54\uc11c\ub4dc\ub4e4\uc744 \ubcf4\uba70 \ud655\uc2e4\ud788 `\uc544\ub294\uac8c \ud798\uc774\ub2e4` \ub77c\ub294\uac78 \ub290\uaf08\ub2e4\\n\\n\\n\\n`Lv.0`\uc744 \ub05d\ub0c8\uc73c\ub2c8 \uc774\uc81c `Lv.1`\uc744 \ucc28\uadfc\ucc28\uadfc \ud480\uc5b4\ubcfc \uc608\uc815\uc774\ub2e4. \uc870\uae08 \ud480\uc5b4 \ubcf4\ub2c8\uae4c `Lv.0`\uc5d0\uc11c \uae30\ucd08\ub97c \ud0c4\ud0c4\ud788 \ub2e4\uc84c\ub2e4\uba74 `Lv.1`\ub3c4 \ud070 \uc5b4\ub824\uc6c0\uc740 \uc5c6\uc744 \uac83 \uac19\ub2e4! \\n\\n\ucc38\uace0\ub85c \ucd08\ubc18\uc5d0\ub294 \uae30\ucd08\uc640 \uc785\ubb38 \ub09c\uc774\ub3c4\uac00 \ube44\uc2b7\ud558\uc9c0\ub9cc, \uc785\ubb38 \ud6c4\ubc18\uc73c\ub85c \uac08\uc218\ub85d \uc5b4\ub824\uc6cc\uc9c4\ub2e4. \uae30\ucd08\uc640 \uc785\ubb38\uc744 \ub530\ub85c \uc9c4\ud589\ud560 \uc0dd\uac01\uc774\ub77c\uba74 \uae30\ucd08 \u2192 \uc785\ubb38 \uc21c\uc11c\ub85c \uacf5\ubd80\ud558\ub294 \uac83\uc744 \ucd94\ucc9c\ud55c\ub2e4.\\n\\n![\ud504\ub85c\uadf8\ub798\uba38\uc2a4 \uc644\ub8cc \uce98\ub9b0\ub354](./img/programmers-cal.png)"},{"id":"intro","metadata":{"permalink":"/blog/intro","editUrl":"https://github.com/eeheueklf/eeheueklf.github.io/tree/main/blog/2025-08-27.md","source":"@site/blog/2025-08-27.md","title":"\uc778\ud2b8\ub85c","description":"\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1","date":"2025-08-27T00:00:00.000Z","formattedDate":"2025\ub144 8\uc6d4 27\uc77c","tags":[],"readingTime":1.4,"hasTruncateMarker":false,"authors":[],"frontMatter":{"slug":"intro","title":"\uc778\ud2b8\ub85c","date":"2025-08-27T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"[\ud68c\uace0] \ud504\ub85c\uadf8\ub798\uba38\uc2a4 \uae30\ucd08 \uc785\ubb38 \ub2ec\uc131 \ud6c4\uae30 \ud83e\udd73\ud83c\udf89","permalink":"/blog/programmers"}},"content":"\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\ud83e\uddf1\\n\\n## \ub9c8\ud06c\ub2e4\uc6b4 \ucc38\uace0\ud558\uae30 \ud83c\udf6a\ud83c\udf44\u200d\ud83d\udfeb\u2615\\n### \ud83d\udc4b \uc548\ub155\ud558\uc138\uc694 \ud83e\udd0e\ud83e\uddf8\ud83d\udcdc\\n#### \uc81c\ubaa9 4 \ud83c\udf15\ud83c\udf5e\ud83c\udf42\\n \ud83c\udf69\ud83d\udc3f\ufe0f\ud83c\udf66\\n\\n## 1. alert\\n\\n:::note\\n\uc815\ubcf4\\n:::\\n\\n:::tip\\n\ud301\\n:::\\n\\n:::warning\\n\uba54\ubaa8\\n:::\\n\\n:::danger\\n\uacbd\uace0\\n:::\\n:::danger Take care\\n\\n\uacbd\uace0\uc785\ub2c8\ub2e4~\\n\\n:::\\n---\\n\\n\\n## 2. \ud14d\uc2a4\ud2b8 \uc2a4\ud0c0\uc77c\\n**\uad75\uac8c**  \\n*\uae30\uc6b8\uc784*  \\n~~\ucde8\uc18c\uc120~~  \\n**\uad75\uace0 _\uae30\uc6b8\uc784_**\\n\\n---\\n\\n## 3. \ubaa9\ub85d\\n### \uc21c\uc11c \uc5c6\ub294 \ubaa9\ub85d\\n- \uc544\uc774\ud15c 1\\n- \uc544\uc774\ud15c 2\\n  - \ud558\uc704 \uc544\uc774\ud15c\\n\\n### \uc21c\uc11c \uc788\ub294 \ubaa9\ub85d\\n1. \uccab \ubc88\uc9f8\\n2. \ub450 \ubc88\uc9f8\\n   1. \ud558\uc704 \uccab \ubc88\uc9f8\\n\\n---\\n\\n## 5. \ucf54\ub4dc\\n```js\\nconsole.log(\\"JavaScript \ucf54\ub4dc \ube14\ub85d\\");\\n```\\n\\n---\\n\\n## 6. \uc778\uc6a9\ubb38\\n> \uc778\uc6a9\ubb38\uc785\ub2c8\ub2e4.\\n>> \uc911\ucca9 \uc778\uc6a9\ubb38\uc785\ub2c8\ub2e4.\\n\\n\\n---\\n\\n## 8. \uccb4\ud06c\ubc15\uc2a4 (GFM)\\n- [x] \uc644\ub8cc\\n- [ ] \ubbf8\uc644\ub8cc\\n\\n---\\n\\n\\n## 10. \uac01\uc8fc\\n\ubb38\uc7a5 \uc548\uc5d0\uc11c \uac01\uc8fc\ub97c \ub2ec \uc218 \uc788\uc2b5\ub2c8\ub2e4[^1].\\n\\n[^1]: \uac01\uc8fc \ub0b4\uc6a9\\n\\n---\\n\\n## 12. \ud615\uad11\ud39c\\n<mark>\uae30\ubcf8 \ud615\uad11\ud39c</mark>\uc774\uc796\uc544~\\n\\n\\n\\n\\n\\n\\n---\\n\\n## 14. \ucf54\ub4dc \ube14\ub85d\\n```js {1,4}\\nfunction hello() {\\n  console.log(\\"2\ubc88 \uc904 \ud558\uc774\ub77c\uc774\ud2b8\\");\\n}\\nconsole.log(\\"4\ubc88 \uc904 \ud558\uc774\ub77c\uc774\ud2b8\\");\\nconsole.log(\\"4\ubc88 \uc904 \ud558\uc774\ub77c\uc774\ud2b8\\");\\nconsole.log(\\"4\ubc88 \uc904 \ud558\uc774\ub77c\uc774\ud2b8\\");\\n```\\n```jsx title=\\"src/pages/my-react-page.js\\"\\nimport React from \'react\';\\nimport Layout from \'@theme/Layout\';\\n\\nexport default function MyReactPage() {\\n  return (\\n    <Layout>\\n      <h1>My React page</h1>\\n      <p>This is a React page</p>\\n    </Layout>\\n  );\\n}\\n```\\n\\n\\n---\\n\\n\\n<details>\\n  <summary>Toggle me!</summary>\\n\\n  This is the detailed content\\n\\n  ```js\\n  console.log(\\"Markdown features including the code block are available\\");\\n  ```\\n</details>"}]}')}}]);